INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Développement d''une application simple (Débutant)', 'Formation pratique pour apprendre à développer une application simple, adaptée aux débutants.', 10, 150000.00, 'entreprise', '2026-02-15', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Comprendre les bases du développement d’applications\n• Découvrir les langages et outils essentiels\n• Apprendre à structurer un projet simple\n• Mettre en pratique avec un mini-projet\n• Acquérir les fondamentaux pour évoluer vers des projets plus complexes\n\n--- OBJECTIFS DÉTAILLÉS ---\nInitier les participants au développement d’applications, leur faire découvrir les outils et langages de base, les guider dans la création d’un projet simple et leur donner les compétences nécessaires pour progresser vers des projets plus avancés.\n\n--- PRÉREQUIS ---\nAucune connaissance préalable requise. Une familiarité avec l’ordinateur est suffisante.\n\n--- CONTENU ---\nModule 1 : Introduction au développement d’applications\nModule 2 : Découverte des langages et outils de base\nModule 3 : Structuration d’un projet simple\nModule 4 : Développement pas à pas d’une application\nModule 5 : Tests et validation\nModule 6 : Présentation et amélioration du projet\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nDébutants en informatique, étudiants, autodidactes et toute personne souhaitant apprendre à créer une application simple.\n\n--- MÉTHODES ---\nCours interactifs, démonstrations, ateliers pratiques, exercices guidés et mini-projet final.\n\n--- SUPPORTS ---\nEnvironnement de développement (IDE), langage de programmation adapté aux débutants (ex. Python, JavaScript), supports PDF, slides et tutoriels pratiques.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
